<template><main class="page grid"><section class="panel"><h1>TerritoryRush</h1><p>{{ messages.nickname }}</p><van-field v-model="auth.nickname" label="昵称" /><div class="flex gap-2 mt-3"><GameButton @click="quick">快速加入</GameButton><GameButton @click="create">创建房间</GameButton></div><p>{{ messages.rules }}</p></section><RoomCard v-for="room in roomStore.rooms.slice(0,2)" :key="room.id" :room="room" @join="join" /></main></template><script setup lang="ts">import { useRouter } from 'vue-router'; import { useAuthStore } from '../stores/authStore'; import { useRoomStore } from '../stores/roomStore'; import GameButton from '../components/common/GameButton.vue'; import RoomCard from '../components/common/RoomCard.vue'; import { messages } from '../constants/messages'; const router=useRouter(); const auth=useAuthStore(); const roomStore=useRoomStore(); function join(id:string){roomStore.join(id);router.push('/room/'+id)} function quick(){const id=roomStore.rooms[0]?.id||roomStore.create();join(id)} function create(){router.push('/room/'+roomStore.create())}</script>
